```bash
awk 'BEGIN{skip=0} 
/^[[:space:]]*static bool planContainsAdditionalSimplifications\(VPlan &Plan,/{
  print "static bool planContainsAdditionalSimplifications(VPlan &Plan,";
  print "                                                  VPCostContext &CostCtx,";
  print "                                                  Loop *TheLoop) {";
  print "  // Collect all instructions represented by VPlan recipes.";
  print "  auto GetInstructionForCost = [](const VPRecipeBase *R) -> Instruction * {";
  print "    if (auto *S = dyn_cast<VPSingleDefRecipe>(R))";
  print "      return dyn_cast_or_null<Instruction>(S->getUnderlyingValue());";
  print "    if (auto *WidenMem = dyn_cast<VPWidenMemoryRecipe>(R))";
  print "      return &WidenMem->getIngredient();";
  print "    return nullptr;";
  print "  };";
  print "  DenseSet<Instruction *> SeenInstrs;";
  print "  auto Iter = vp_depth_first_deep(Plan.getVectorLoopRegion()->getEntry());";
  print "  for (VPBasicBlock *VPBB : VPBlockUtils::blocksOnly<VPBasicBlock>(Iter)) {";
  print "    for (VPRecipeBase &R : *VPBB) {";
  print "      if (auto *IR = dyn_cast<VPInterleaveRecipe>(&R)) {";
  print "        auto *IG = IR->getInterleaveGroup();";
  print "        unsigned NumMembers = IG->getNumMembers();";
  print "        for (unsigned I = 0; I != NumMembers; ++I)";
  print "          if (Instruction *M = IG->getMember(I))";
  print "            SeenInstrs.insert(M);";
  print "        continue;";
  print "      }";
  print "      if (Instruction *UI = GetInstructionForCost(&R))";
  print "        SeenInstrs.insert(UI);";
  print "    }";
  print "  }";
  print "  // Detect extra simplifications: loop instructions not represented in VPlan";
  print "  // and not skipped for cost computation.";
  print "  bool ExtraSimplifications = any_of(TheLoop->blocks(), [&SeenInstrs, &CostCtx,";
  print "                                    TheLoop](BasicBlock *BB) {";
  print "    return any_of(*BB, [&SeenInstrs, &CostCtx, TheLoop, BB](Instruction &I) {";
  print "      if (isa<PHINode>(&I) && BB == TheLoop->getHeader())";
  print "        return false;";
  print "      return !SeenInstrs.contains(&I) && !CostCtx.skipCostComputation(&I, true);";
  print "    });";
  print "  });";
  print "  if (ExtraSimplifications)";
  print "    return true;";
  print "  // Heuristic: a select with a loop-invariant condition may allow";
  print "  // VPlan-based cost model to exploit uniform predicates not reflected";
  print "  // in the legacy cost model. Treat its presence as an additional";
  print "  // simplification so disagreement on VF does not trigger the assert.";
  print "  for (BasicBlock *BB : TheLoop->blocks()) {";
  print "    for (Instruction &I : *BB) {";
  print "      if (auto *SI = dyn_cast<SelectInst>(&I)) {";
  print "        if (TheLoop->isLoopInvariant(SI->getOperand(0)))";
  print "          return true;";
  print "      }";
  print "    }";
  print "  }";
  print "  return false;";
  print "}";
  skip=1; next
}
