```bash
awk '{
  print
  if ($0 ~ /if \(auto \*SI = dyn_cast<SelectInst>\(&I\)\) {/) insert=1
  else if (insert && $0 ~ /if \(TheLoop->isLoopInvariant\(SI->getOperand\(0\)\)\)/) after_invariant=1
  else if (after_invariant) {
    # After the existing loop-invariant check, insert heuristic for condition instruction with invariant operands.
    print "          // Heuristic extension: if the select condition is an instruction";
    print "          // (e.g. an icmp) whose operands are all loop-invariant, treat it";
    print "          // as an additional simplification (uniform predicate usage).";
    print "          if (auto *CondI = dyn_cast<Instruction>(SI->getOperand(0))) {";
    print "            bool AllInv = true;";
    print "            for (Value *Op : CondI->operands())";
    print "              if (!TheLoop->isLoopInvariant(Op)) { AllInv = false; break; }";
    print "            if (AllInv)";
